ALTER TABLE main.pii_data.bronze_etoro_history_customer SET TBLPROPERTIES (
    'comment' = 'Slowly Changing Dimension Type 2 (SCD2) versioned history of every customer profile change, storing a complete snapshot of Customer.CustomerStatic for every modification with ValidFrom/ValidTo timestamps to enable point-in-time profile reconstruction. Source: etoro.History.Customer on the etoro production database, ingested via the Generic Pipeline (Append strategy, 1440-minute refresh). Doc source: Tier 1 wiki (knowledge/ProdSchemas/DB_Schema/etoro/Wiki/History/Tables/History.Customer.md).'
);

