-- Column Comments
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN CustomerVersionID COMMENT 'Surrogate PK for this version record. CLUSTERED PK with PAGE compression. NOT FOR REPLICATION prevents identity gaps during replication. Monotonically increasing - higher = newer version. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN ValidFrom COMMENT 'UTC timestamp when this version became the active profile state. Equals the update timestamp in Customer.CustomerStatic that triggered the history insert. Covered by COLUMNSTORE index for DWH temporal queries. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN ValidTo COMMENT 'UTC timestamp when this version was superseded by the next. Sentinel value ''3000-01-01'' indicates the current (still-active) version. Indexed via IX_HistoryCustomer_ValidToCID for efficient "get current" and range queries. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN CID COMMENT 'Customer ID - the eToro account identifier. Same as Customer.CustomerStatic.CID. Multiple rows with the same CID represent that customer''s version history. Indexed via IX_HistoryCustomer_ValidToCID (ValidTo, CID) and Idx_HistoryCustomer_CID_CustomerVersionID (CID, CustomerVersionID DESC). (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN ProviderID COMMENT 'Platform/white-label provider ID for this customer''s account. Inherited from Customer.CustomerStatic. Identifies which eToro entity or white-label partner the account belongs to. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN CountryID COMMENT 'Country of residence at this version point. Changes may occur due to customer address updates or regulatory migration. References Dictionary.Country. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN StateID COMMENT 'State/province within the country. References Dictionary.State or similar. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN LanguageID COMMENT 'UI language preference at this version point. References Dictionary.Language. See Language. Historically listed in glossary Used By for Customer.CustomerStatic - same semantics apply here. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN CommunicationLanguageID COMMENT 'Language used for emails and notifications, which may differ from the UI language. References Dictionary.Language. See Language. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN CurrencyID COMMENT 'Account denomination currency at this version point. Changes to account currency are tracked as a new version. References Dictionary.Currency. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN TimeZoneID COMMENT 'Customer''s configured timezone preference. References Dictionary.TimeZone or similar. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN PlayerStatusID COMMENT 'Account compliance/trading restriction state at this version. One of the most frequently changing fields - status changes (block, unblock, restrict) generate a new version. See Player Status. Values: 1=Normal, 2=Blocked, etc. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN CampaignID COMMENT 'Marketing campaign attribution at acquisition time. Usually set once at registration and unchanged. NULL for organically acquired customers. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN PlayerLevelID COMMENT 'Customer''s trading experience/privilege level at this version. Covered by COLUMNSTORE index (PlayerLevelID) - frequently used in DWH queries to analyse customer segment distribution over time. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN TradeLevelID COMMENT 'Trading tier level classification. Determines fee structures and trading limits applicable at this version. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN SpreadGroupID COMMENT 'Spread group assignment at this version point. Controls bid/ask spread applied to the customer''s trades. References Trade.SpreadGroup or similar. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN LabelID COMMENT 'Customer label/tag classification. Covered by COLUMNSTORE index - used in DWH segment analysis over time. References Dictionary.Label or BackOffice.Label. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN UserName COMMENT 'eToro username. MASKED WITH (FUNCTION = ''default()'') - PII. Username rarely changes but a change generates a new version. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN Password COMMENT 'Hashed password at this version point. Password changes generate a new version entry (historical password audit). NOT masked in DDL but is a hashed value, not plaintext. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN IsReal COMMENT 'Whether this is a real-money account (1) or a demo/paper-trading account (0). Live data shows all recent rows = 1 (real). Demo accounts have CIDs typically beginning with 3 or 4 (negative or high range). (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN BirthDate COMMENT 'Customer date of birth. MASKED WITH (FUNCTION = ''default()''). Required for KYC age verification. Rarely changes; version created if corrected. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN Gender COMMENT 'M/F/NULL gender. Nullable - many customers do not provide gender. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN FirstName COMMENT 'Customer''s first name. MASKED WITH (FUNCTION = ''default()''). PII. Changes when customer updates their profile details. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN LastName COMMENT 'Customer''s last name. MASKED WITH (FUNCTION = ''default()''). PII. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN Address COMMENT 'Street address line. MASKED WITH (FUNCTION = ''default()''). PII. Address changes (e.g., on KYC document submission) create new versions. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN City COMMENT 'City of residence. Not masked (city is lower-sensitivity PII). (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN Zip COMMENT 'Postal/ZIP code. MASKED WITH (FUNCTION = ''default()''). PII. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN Email COMMENT 'Customer email address. MASKED WITH (FUNCTION = ''default()''). Email changes trigger a new version and historically required re-verification. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN IsEmailVerified COMMENT 'Whether the email was verified at this version. 1 = verified; 0 or NULL = unverified. Changes as customer completes email verification. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN Phone COMMENT 'Primary phone number. MASKED WITH (FUNCTION = ''default()''). PII. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN Fax COMMENT 'Fax number (legacy field). Rarely populated in modern accounts. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN Mobile COMMENT 'Mobile phone number. MASKED WITH (FUNCTION = ''default()''). PII. Used for 2FA and SMS notifications. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN Comments COMMENT 'Internal notes or comments on the customer. Free-text field. Large field (8000 chars), stored in TEXTIMAGE_ON HISTORY filegroup. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN SerialID COMMENT 'Sequential serial number for the customer account. Legacy field from early eToro platform. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN AccountExpirationDate COMMENT 'Date when the account is scheduled to expire. NULL for permanent accounts. Used for demo accounts with time-limited access. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN HelpDeskType COMMENT 'Customer support routing classification. Determines which support queue or agent group handles this customer. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN LotCountGroupID COMMENT 'Lot size group assignment. DEFAULT = 0. Controls minimum lot/unit sizes for trading. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN PrivacyPolicyID COMMENT 'Version of the eToro Privacy Policy the customer accepted at this version point. Updates when customer accepts a new policy version. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN GCID COMMENT 'Global Customer ID - the household/person-level identifier linking all accounts belonging to the same real-world person. May be NULL for old accounts pre-GCID system. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN WeekendFeePrecentage COMMENT 'Weekend/overnight fee percentage applied to this customer''s open positions. DEFAULT = 100 (full standard fee). Reduced for VIP customers or specific promotions. Note: "Precentage" is a legacy typo in the column name. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN IsEmailActivated COMMENT 'Whether the customer''s account email was activated (email link clicked after registration). 1 = activated; 0 = not activated; NULL = legacy. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN AccountStatusID COMMENT 'Open/closed state of the account. See Account Status. Values: 1 = Open (active), 2 = Closed. NULL for legacy accounts pre-AccountStatusID addition. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN PendingClosureStatusID COMMENT 'Sub-state when account is in process of being closed. NULL for normally active accounts. Set when a closure request is submitted and the account is in the closure workflow. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN PhonePrefix COMMENT 'International dialling prefix (e.g., "+1", "+44"). Stored separately from PhoneBody for standardized international number handling. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN PhoneBody COMMENT 'Phone number without the prefix. MASKED WITH (FUNCTION = ''default()''). PII. Used for SMS/voice communications. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN RegionID COMMENT 'Geographic region by customer''s declared residence. See Region. Used for marketing segmentation and default currency assignment. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN RegionByIP_ID COMMENT 'Geographic region detected from the customer''s IP address at registration. May differ from RegionID (declared vs detected). Used for fraud and compliance geo-risk analysis. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN OptOutReasonID COMMENT 'Reason the customer opted out of marketing communications. NULL if not opted out. References a lookup table for opt-out reasons. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN MiddleName COMMENT 'Customer''s middle name. MASKED WITH (FUNCTION = ''default()''). PII. Optional field - NULL for customers without a middle name or who didn''t provide it. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN CitizenshipCountryID COMMENT 'Country of citizenship (may differ from CountryID which is country of residence). Required for some regulatory KYC processes. References Dictionary.Country. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN PlayerStatusReasonID COMMENT 'Reason code for the current PlayerStatus. Used when PlayerStatus is non-Normal (e.g., reason for blocking). See Player Status. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN Trace COMMENT 'Session audit JSON automatically generated by the DEFAULT constraint on each INSERT. Contains: HostName, AppName, SUserName, OriginalLogin, SPID, DBName, ObjectName. Identifies the source application and stored procedure that triggered this version creation. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN SubRegionID COMMENT 'Sub-region within the customer''s region (e.g., state-level granularity beyond StateID). Used for fine-grained geographic marketing segmentation. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN EmailVerificationProviderID COMMENT 'Service used to verify the customer''s email address (e.g., internal, SendGrid, third-party). NULL for accounts pre-email-verification-provider tracking. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN PlayerStatusSubReasonID COMMENT 'Hierarchical sub-reason code under PlayerStatusReasonID. Provides additional granularity for compliance and operations when setting or reviewing account restrictions. See Player Status. (Tier 1 - upstream wiki, etoro.History.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_history_customer ALTER COLUMN BuildingNumber COMMENT 'Building/apartment number as a separate address component. Supports structured address formats for certain regulatory jurisdictions where this must be explicitly captured. (Tier 1 - upstream wiki, etoro.History.Customer)';

